import React from 'react';
import { Link } from 'react-router-dom';
import '../styles/MovieCard.css';

const MovieCard = ({ movie, onDelete }) => {
  const { _id, title, year, genre, rating, status, posterUrl, review } = movie;

  // Заглушка для постера, если URL не указан
  const poster = posterUrl || '/default-poster.jpg';

  // Форматирование рейтинга до одного знака после запятой
  const formattedRating = rating ? Number(rating).toFixed(1) : null;

  return (
    <div className="movie-card">
      <div className="poster-container">
        <img src={poster} alt={title} className="movie-poster" />
      </div>

      <div className="movie-info">
        <h3 className="movie-title">{title} <span className="movie-year">({year})</span></h3>

        <div className="movie-meta">
          {formattedRating && (
            <span className="badge rating">
              <i className='bx bx-star'></i> {formattedRating}
            </span>
          )}
          {genre && <span className="badge genre">{genre}</span>}
          {status && (
            <span className={`badge status status-${status.replace(/\s+/g, '-')}`}>
              {status}
            </span>
          )}
        </div>

        {review && (
          <p className="movie-review-preview">
            <i className='bx bx-quote-alt-left'></i>
            {review.length > 60 ? `${review.substring(0, 60)}...` : review}
          </p>
        )}

        <div className="card-actions">
          <Link to={`/movies/edit/${_id}`} className="btn-icon edit-btn">
            <i className='bx bx-edit'></i> Edit
          </Link>
          <button onClick={() => onDelete(_id)} className="btn-icon delete-btn">
            <i className='bx bx-trash'></i> Delete
          </button>
        </div>
      </div>
    </div>
  );
};

export default MovieCard;
